/**
 * lib/core/marp-bundle.js
 *
 * The pure, fs-free spec for an "Export to Marp" bundle — the SINGLE source of
 * truth shared by both producers so they can't drift:
 *
 *   1. tools/export-marp.js  — the Node CLI (reads asset bytes from disk, zips
 *      via the `zip` binary).
 *   2. the Drawing Board      — the in-browser export (fetches asset bytes over
 *      HTTP, zips via JSZip), through the playground engine bundle.
 *
 * This module owns: the generated text files (README, marp.config.cjs,
 * package.json), the trailing runtime `<script>` block appended to the deck, the
 * filename sanitizer, and the ASSET manifest (which static files the bundle
 * carries and where). It does NOT read files or know about transport — each
 * producer supplies the bytes for the manifest entries. The split baking lives
 * in lib/core/bake-splits.js (also shared); asset localization is producer-side.
 */

const LATTICE_VERSION = '1.0.0';
const MARP_CLI_RANGE = '^4.3.1';

// Static assets every bundle carries, as { from, to } where `from` is the repo
// path (CLI) / served basename (browser) and `to` is the path inside the bundle.
// The MINIFIED engine + stylesheet are shipped under the canonical names the
// emulator resolves (dist/lattice-emulator.js, dist/lattice.css) to stay lean.
const STATIC_ASSETS = Object.freeze([
  { from: 'dist/lattice.min.css', to: 'dist/lattice.css' },
  { from: 'dist/lattice-emulator.min.js', to: 'dist/lattice-emulator.js' },
  { from: 'dist/lattice-runtime.min.js', to: 'lattice-runtime.min.js' },
  { from: 'mermaid-v11.min.js', to: 'mermaid-v11.min.js' },
]);

/** Deck → a filesystem-safe slug for the bundle/zip name. */
function safeName(name) {
  return (name || 'deck').trim().replace(/[^\w.-]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 60) || 'deck';
}

// Appended to the exported deck's markdown (at EOF). The bundled mermaid + the
// Lattice browser runtime render diagrams and structural components CLIENT-SIDE
// when the deck is opened as HTML in a browser. The markdownlint-disable keeps
// the inline <script> tags from tripping MD033 when the .md is edited.
const RUNTIME_SCRIPTS = [
  '',
  '<!-- markdownlint-disable MD033 -->',
  '<script src="mermaid-v11.min.js"></script>',
  '<script src="lattice-runtime.min.js"></script>',
  '',
].join('\n');

/** Append the runtime scripts to a (baked, front-matter-included) deck source. */
function withRuntimeScripts(deckSource) {
  return `${deckSource.replace(/\s*$/, '')}\n${RUNTIME_SCRIPTS}`;
}

// The marp-cli config: register the bundled theme CSS so `marp` splits (via the
// baked `---`) and styles the deck. It does NOT wire a render-time engine —
// Lattice no longer ships a marp engine. Server-side structural transforms
// (charts, forms, card grids) come from the FULL-FIDELITY paths every bundle
// carries: the zero-install `dist/lattice-emulator.js` (the README's primary
// route) and, for HTML opened in a browser, the bundled `lattice-runtime.min.js`
// which renders diagrams + components client-side. The marp-cli path is the
// split-and-theme convenience for people who already use marp.
const MARP_CONFIG_CJS = `// Auto-generated by Lattice "Export to Marp".
const fs = require('fs');
const path = require('path');
const themeSet = [
  path.join(__dirname, 'dist', 'lattice.css'),
  ...fs.readdirSync(path.join(__dirname, 'themes')).map((f) => path.join(__dirname, 'themes', f)),
];
module.exports = { themeSet, allowLocalFiles: true };
`;

/** package.json for the bundle (pins marp-cli + the lattice engine). */
function packageJson(name) {
  return {
    name: `${safeName(name)}-marp-export`,
    private: true,
    description: `Portable Marp bundle of the "${name}" Lattice deck`,
    scripts: {
      pdf: `marp ${name}.md --config-file marp.config.cjs --allow-local-files -o ${name}.pdf`,
      html: `marp ${name}.md --config-file marp.config.cjs --allow-local-files -o ${name}.html`,
    },
    dependencies: {
      '@marp-team/marp-cli': MARP_CLI_RANGE,
      '@slidewright/lattice': `^${LATTICE_VERSION}`,
    },
  };
}

/** README.md for the bundle. `themes` is the list of bundled theme paths. */
function readme({ name, palette, themes }) {
  return `# ${name} — portable Marp bundle

Exported from Lattice. The deck's slide splits are **baked into literal \`---\`**,
so it divides correctly in any Marp tool — no Lattice plugin required.

## Render it (full fidelity)

**Zero install** — the Lattice engine is bundled:

\`\`\`sh
node dist/lattice-emulator.js ${name}.md ${name}.pdf ${palette}
\`\`\`

(PDF export needs a local Chrome/Chromium.) This is the recommended route — it
renders the whole deck, including charts, forms, and structural layouts.

**With the standard Marp CLI** (splits + themes only):

\`\`\`sh
npm install
npm run pdf      # → ${name}.pdf   (or: npm run html)
\`\`\`

Marp renders the slides and applies the palette, but it does **not** draw
Lattice's structural components (charts, card grids, split panels, badge
tables) — those need the bundled engine above, or the browser route below.

## Open the HTML in a browser (diagrams + components, no install)

\`${name}.html\` (from \`npm run html\`, or any Marp HTML export of \`${name}.md\`)
loads the bundled \`mermaid-v11.min.js\` + \`lattice-runtime.min.js\` via two
\`<script>\` tags at the end of the deck. Opened in a browser they render
Mermaid/chart diagrams **and** the structural layouts (card grids, split panels,
islands, badge tables) client-side — so the HTML shows the full deck even though
plain Marp didn't draw them.

## Quick preview (VS Code)

Open \`${name}.md\` with the Marp for VS Code extension after pointing
\`markdown.marp.themes\` at the files in \`themes/\` (${themes.join(', ')}).
Slides split and style correctly. (The VS Code preview blocks inline scripts, so
diagrams/components show there only via the full-fidelity commands above or the
HTML-in-a-browser route.)

## What's in here

| Path | What |
|---|---|
| \`${name}.md\` | the deck — splits baked to \`---\`, image paths localized |
| \`dist/lattice.css\` | the palette-blind engine stylesheet (minified) |
| \`dist/lattice-emulator.js\` | the bundled Lattice renderer (minified, zero-install) |
| \`themes/\` | the \`${palette}\` palette (+ dark) |
| \`assets/\` | local images the deck references |
| \`mermaid-v11.min.js\`, \`lattice-runtime.min.js\` | render diagrams + components in the browser (loaded by the deck's trailing \`<script>\` tags) |
| \`marp.config.cjs\` | Marp CLI config (registers the themes; splits + styles only) |
`;
}

module.exports = {
  STATIC_ASSETS,
  RUNTIME_SCRIPTS,
  MARP_CONFIG_CJS,
  withRuntimeScripts,
  safeName,
  packageJson,
  readme,
};
